SELECT t.*, s.username as seller_username, b.username as buyer_username, p.product_name, p.category FROM trades t LEFT JOIN users s ON t.seller_student_id = s.student_id LEFT JOIN users b ON t.buyer_student_id = b.student_id LEFT JOIN products p ON t.product_id = p.product_id
AND (t.seller_student_id = #{studentId} OR t.buyer_student_id = #{studentId})
AND t.trade_date >= #{startDate}
AND t.trade_date <= #{endDate}
AND t.trade_status = #{tradeStatus}
ORDER BY t.trade_date DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM trades t


        AND (t.seller_student_id = #{studentId} OR t.buyer_student_id = #{studentId})


        AND t.trade_date >= #{startDate}


        AND t.trade_date <= #{endDate}


        AND t.trade_status = #{tradeStatus}

SELECT p.category, COUNT(*) as count FROM trades t LEFT JOIN products p ON t.product_id = p.product_id WHERE t.trade_status = '已完成'
AND t.trade_date BETWEEN #{startDate} AND #{endDate}
GROUP BY p.category ORDER BY count DESC
